mkdir -p /tmp/stackalloc_test && cd /tmp/stackalloc_test && dotnet new console --force -o . -n StackallocTest --no-restore 2>&1 | tail -1 && cat <<'EOF' > Program.cs
using System;

unsafe
{
    Span<nint> span = stackalloc nint[4];
    span[0] = 10;
    span[1] = 20;
    span[2] = 30;
    span[3] = 40;

    Console.WriteLine($"Length: {span.Length}");
    for (int i = 0; i < span.Length; i++)
        Console.WriteLine($"span[{i}] = {span[i]}");

    Console.WriteLine($"Element size: {sizeof(nint)} bytes");
}
EOF
cat <<'EOF' > StackallocTest.csproj
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
    <AllowUnsafeBlocks>true</AllowUnsafeBlocks>
  </PropertyGroup>
</Project>
EOF
dotnet run 2>&1

